+            .Select((sentence, index) => (Sentence: sentence, Score: ScoreSentence(sentence, wordFrequencies), Index: index))
+            .OrderByDescending(s => s.Score)
+            .Take(maxSentences)
+            .OrderBy(s => s.Index) // preserve original order
+            .Select(s => s.Sentence);
+
+        return string.Join(" ", scored);
+    }
+
+    private static List<string> SplitIntoSentences(string text)
+    {
+        return SentenceRegex().Matches(text)
+            .Select(m => m.Value.Trim())
+            .Where(s => s.Length > 0)
+            .ToList();
+    }
+
+    private static Dictionary<string, double> ComputeWordFrequencies(List<string> sentences)
+    {
+        var freq = new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase);
+
+        foreach (var sentence in sentences)
+        {
+            foreach (var word in TokenizeWords(sentence))
+            {
+                if (StopWords.Contains(word.ToLowerInvariant()) || word.Length < 2)
+                    continue;
+
+                var key = word.ToLowerInvariant();
+                freq[key] = freq.GetValueOrDefault(key) + 1;
+            }
+        }
+
+        if (freq.Count == 0)
+            return freq;
+
+        // Normalize by maximum frequency
+        var max = freq.Values.Max();
+        foreach (var key in freq.Keys)
+            freq[key] /= max;
+
+        return freq;
+    }
+
+    private static double ScoreSentence(string sentence, Dictionary<string, double> wordFrequencies)
+    {
+        var words = TokenizeWords(sentence);
+        if (words.Count == 0)
+            return 0;
+
+        return words.Sum(w => wordFrequencies.GetValueOrDefault(w.ToLowerInvariant()));
+    }
+
+    private static List<string> TokenizeWords(string text)
+    {
+        return WordRegex().Matches(text)
+            .Select(m => m.Value)
+            .ToList();
+    }
+
+    [GeneratedRegex(@"[^.!?]*[.!?]+|[^.!?]+$", RegexOptions.Compiled)]
+    private static partial Regex SentenceRegex();
+
+    [GeneratedRegex(@"\b[a-zA-Z']+\b", RegexOptions.Compiled)]
+    private static partial Regex WordRegex();
+}
